from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a descriptor (without repeating the subject)
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language descriptor for a single predicate."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            # Return a phrase that can be used after the subject, e.g., "is American"
            low_obj = obj.lower()
            if low_obj in ("united states", "usa", "united states of america"):
                adj = "American"
            elif low_obj.startswith("the "):
                adj = obj[4:].strip()
            else:
                # Try to form an adjective by adding 'ian' if not already an adjective
                adj = obj
            return f"is {adj}"
        if p == "occupation":
            # Use a more natural verb for astronauts' roles
            return f"served as a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "mission":
            # Assume subject is an astronaut; describe crew membership in the mission
            return f"was a crew member of {obj}"
        if p == "dateofretirement":
            # Phrase retirement date naturally
            try:
                from datetime import datetime
                dt = datetime.strptime(obj.strip('"'), "%B %Y")
                return f"retired in {dt.strftime('%B %Y')}"
            except Exception:
                # Fallback to generic wording
                return f"retired on {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"operated by {obj}"
        if p == "commander":
            # Express that the object commanded the mission (subject)
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            # Express that the object was the backup pilot for the mission (subject)
            return f"{obj} was the backup pilot of {subj}"
        if p == "crewmembers":
            # Express crew membership relative to the mission (subject)
            return f"{obj} was a crew member of {subj}"
        if p == "leader":
            # Express that the object leads the entity (subject)
            return f"{obj} is the leader of {subj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # Generic fallback
        return f"is {obj}"

    # Group triples by subject
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)

    sentences = []
    for subj, items in groups.items():
        # No special handling; treat all predicates uniformly
        subject_phrase = subj
        remaining_items = items

        # Separate descriptors that already contain the subject (e.g., “Frank Borman was the commander of Apollo 8”)
        # from those that need the subject prefixed (e.g., “was born in Texas”).
        prefixed = []
        full_statements = []
        for t in remaining_items:
            d = phrase(subj, t.predicate, t.object)
            if subj in d:
                full_statements.append(d)
            else:
                prefixed.append(d)

        # Build sentence(s) for the current subject.
        subject_sent = ""
        if prefixed:
            if len(prefixed) == 1:
                subject_sent = f"{subject_phrase} {prefixed[0]}"
            else:
                body = ", ".join(prefixed[:-1])
                subject_sent = f"{subject_phrase} {body}, and {prefixed[-1]}"
            subject_sent += "."

        # Append any full statements that already mention the subject.
        if full_statements:
            # Join them with commas and a final conjunction for fluency.
            if len(full_statements) == 1:
                stmt = full_statements[0] + "."
            else:
                stmt_body = ", ".join(full_statements[:-1])
                stmt = f"{stmt_body}, and {full_statements[-1]}."
            # If we already have a subject‑prefixed sentence, concatenate with a space.
            if subject_sent:
                sentences.append(f"{subject_sent} {stmt}")
            else:
                sentences.append(stmt)
        else:
            # Only prefixed descriptors exist.
            sentences.append(subject_sent)

    # Combine sentences for different subjects
    return " ".join(sentences)

